#include <stdio.h>
#include <stdlib.h>

// Structure for a heap node
typedef struct Node {
    int value;
} Node;

// Function to swap two nodes
void swap(Node *a, Node *b) {
    Node temp = *a;
    *a = *b;
    *b = temp;
}

// Function to heapify the array
void heapify(Node *arr, int n, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < n && arr[left].value > arr[largest].value)
        largest = left;

    if (right < n && arr[right].value > arr[largest].value)
        largest = right;

    if (largest != i) {
        swap(&arr[i], &arr[largest]);
        heapify(arr, n, largest);
    }
}

// Function to build a max heap
void buildHeap(Node *arr, int n) {
    for (int i = n / 2 - 1; i >= 0; i--)
        heapify(arr, n, i);
}

// Function to extract the maximum element from the heap
int extractMax(Node *arr, int *n) {
    int max = arr[0].value;
    arr[0] = arr[*n - 1];
    (*n)--;
    heapify(arr, *n, 0);
    return max;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    Node *arr = (Node *)malloc(n * sizeof(Node));

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i].value);
    }

    buildHeap(arr, n);

    for (int i = 0; i < k - 1; i++) {
        extractMax(arr, &n);
    }

    printf("%d\n", arr[0].value);

    free(arr);

    return 0;
}

