import java.util.*;
import java.lang.*;
import java.io.*;

class Heap {
    Vector<Integer> v = new Vector<>();

    void insert(int value) {
        v.add(value);
        int curIndex = v.size() - 1;

        while (curIndex != 0) {
            int parentIndex = (curIndex - 1) / 2;
            if (v.get(parentIndex) < v.get(curIndex)) {
                int temp = v.get(parentIndex);
                v.set(parentIndex, v.get(curIndex));
                v.set(curIndex, temp);
            }
            curIndex = parentIndex;
        }
    }

    void heapify(int index) {
        int leftChild = 2 * index + 1;
        int rightChild = 2 * index + 2;

        if (leftChild < v.size() && v.get(leftChild) > v.get(index)) {
            int temp = v.get(leftChild);
            v.set(leftChild, v.get(index));
            v.set(index, temp);
            heapify(leftChild);
        }

        if (rightChild < v.size() && v.get(rightChild) > v.get(index)) {
            int temp = v.get(rightChild);
            v.set(rightChild, v.get(index));
            v.set(index, temp);
            heapify(rightChild);
        }
    }

    void deleteFromHeap() {
        int index = 0;
        int lastIndex = v.size() - 1;
        v.set(index, v.get(lastIndex));
        v.remove(lastIndex);
        heapify(index);
    }
}

class Main
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Heap h1 = new Heap();
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        int k = scanner.nextInt();

        for (int i = 0; i < n; i++) {
            int value = scanner.nextInt();
            h1.insert(value);
        }

        for (int i = 0; i < k - 1; i++) {
            h1.deleteFromHeap();
        }

        System.out.println(h1.v.get(0));
    }
}

