class Heap {
    constructor() {
        this.v = [];
    }

    insert(value) {
        this.v.push(value);
        let curIndex = this.v.length - 1;

        while (curIndex !== 0) {
            let parentIndex = Math.floor((curIndex - 1) / 2);
            if (this.v[parentIndex] < this.v[curIndex]) {
                [this.v[parentIndex], this.v[curIndex]] = [this.v[curIndex], this.v[parentIndex]];
            }
            curIndex = parentIndex;
        }
    }

    heapify(index) {
        let leftChild = 2 * index + 1;
        let rightChild = 2 * index + 2;
        let largest = index;

        if (leftChild < this.v.length && this.v[leftChild] > this.v[largest]) {
            largest = leftChild;
        }

        if (rightChild < this.v.length && this.v[rightChild] > this.v[largest]) {
            largest = rightChild;
        }

        if (largest !== index) {
            [this.v[index], this.v[largest]] = [this.v[largest], this.v[index]];
            this.heapify(largest);
        }
    }

    deleteFromHeap() {
        let index = 0;
        let lastIndex = this.v.length - 1;
        this.v[index] = this.v[lastIndex];
        this.v.pop();
        this.heapify(index);
    }
}

function findKthLargest(N, K, array) {
    const h1 = new Heap();

    for (let i = 0; i < N; i++) {
        h1.insert(array[i]);
    }

    for (let i = 0; i < K - 1; i++) {
        h1.deleteFromHeap();
    }

    return h1.v[0];
}

function main() {
    const firstLine = readline().split(' ').map(Number);
    const N = firstLine[0];
    const K = firstLine[1];
    const array = readline().split(' ').map(Number);

    const result = findKthLargest(N, K, array);
    console.log(result);
}

